	@Override
	public boolean supportsJoinEstimation() {
		if (sketchBasedJoinEstimator == null) {
			return false;
		}
		long now = System.currentTimeMillis();
		long revisionId = valueStore.getRevision().getRevisionId();
		if (now < joinSupportCacheExpiryMs && revisionId == joinSupportCacheRevisionId) {
			return joinSupportCacheValue;
		}

		boolean ready = sketchBasedJoinEstimator.isReadyNonBlocking();
		joinSupportCacheValue = ready;
		joinSupportCacheRevisionId = revisionId;
		joinSupportCacheExpiryMs = now + JOIN_SUPPORT_CACHE_TTL_MS;
		return ready;
	}

	@Override
	public boolean supportsFilterSelectivityCosting() {
		return sketchBasedJoinEstimator != null;
	}

	@Override
	public PredicateObjectGuarantee getPredicateObjectGuarantee(IRI predicate) {
		return getKnownPredicateObjectGuarantee(predicate).orElse(PredicateObjectGuarantee.NONE);
	}

	@Override
	public Optional<PredicateObjectGuarantee> getKnownPredicateObjectGuarantee(IRI predicate) {
		if (predicate == null) {
			return Optional.empty();
		}
		try {
			long predicateId = valueStore.getId(predicate);
			if (predicateId == LmdbValue.UNKNOWN_ID) {
				return Optional.empty();
			}
			return tripleStore.getKnownPredicateObjectGuarantee(predicateId);
		} catch (IOException e) {
			log.debug("Unable to read LMDB predicate object guarantee for {}", predicate, e);
			return Optional.empty();
		}
	}

	@Override
	public QueryOptimizationScope beginQueryOptimizationScope() {
		if (sketchBasedJoinEstimator == null) {
			return QueryOptimizationScopeProvider.NO_OP_SCOPE;
		}
		QueryOptimizationScope sketchScope = sketchBasedJoinEstimator.beginQueryOptimizationScope();
		OptimizationCostScope costScope = optimizationCostScope.get();
		if (costScope == null) {
			costScope = new OptimizationCostScope();
			optimizationCostScope.set(costScope);
		}
		costScope.depth++;
		return () -> {
			try {
				sketchScope.close();
			} finally {
				closeOptimizationCostScope();
			}
		};
	}

	private void closeOptimizationCostScope() {
		OptimizationCostScope costScope = optimizationCostScope.get();
		if (costScope == null) {
			return;
		}
		costScope.depth--;
		if (costScope.depth <= 0) {
			optimizationCostScope.remove();
		}
	}

