	@Override
	public PlanningAttempt planJoinOrderAttempt(List<TupleExpr> args, Set<String> initiallyBoundVars,
			Algorithm algorithm, List<FilterConstraint> deferredFilters) {
		if (!supportsJoinEstimation()) {
			return PlanningAttempt.rejected("lmdb-sketch", algorithm,
					"ROBUST_NOT_READY", null,
					List.of("rejected: sketch estimator not ready"));
		}
		if (shouldTryBoundedGreedyFirst(args, algorithm, deferredFilters)) {
			PlanningAttempt boundedGreedyAttempt = toLmdbPlanningAttempt(sketchBasedJoinEstimator
					.planJoinOrderAttempt(args, initiallyBoundVars, Algorithm.GREEDY, this, deferredFilters));
			if (isBoundedGreedyPlan(boundedGreedyAttempt)) {
				return withDecisionTrace(boundedGreedyAttempt, boundedGreedySelectedTrace(boundedGreedyAttempt));
			}
			PlanningAttempt selectedAttempt = toLmdbPlanningAttempt(sketchBasedJoinEstimator
					.planJoinOrderAttempt(args, initiallyBoundVars, algorithm, this, deferredFilters));
			return withDecisionTrace(selectedAttempt,
					boundedGreedyRejectedTrace(boundedGreedyAttempt, selectedAttempt));
		}
		PlanningAttempt attempt = sketchBasedJoinEstimator.planJoinOrderAttempt(args, initiallyBoundVars, algorithm,
				this, deferredFilters);
		PlanningAttempt selectedAttempt = toLmdbPlanningAttempt(attempt);
		return withDecisionTrace(selectedAttempt, selectedPlannerTrace(selectedAttempt));
	}

	private boolean shouldTryBoundedGreedyFirst(List<TupleExpr> args, Algorithm algorithm,
			List<FilterConstraint> deferredFilters) {
		if (algorithm != Algorithm.DYNAMIC_PROGRAMMING || args == null || args.isEmpty()) {
			return false;
		}
		int filterCount = deferredFilters == null ? 0 : deferredFilters.size();
		return args.size() + filterCount >= BOUNDED_GREEDY_MIN_ACTIONS;
	}

	private boolean isBoundedGreedyPlan(PlanningAttempt attempt) {
		if (attempt.getAlgorithm() != Algorithm.GREEDY || attempt.getPlan().isEmpty()) {
			return false;
		}
		JoinOrderPlan plan = attempt.getPlan().get();
		return isSmallBoundedGreedyPlan(plan) || isFiniteDirectLookupGreedyPlan(plan);
	}

	private PlanningAttempt withDecisionTrace(PlanningAttempt attempt, String decisionTrace) {
		if (attempt.getPlan().isEmpty() || decisionTrace == null || decisionTrace.isEmpty()) {
			return attempt;
		}
		JoinOrderPlan plan = attempt.getPlan().get();
		Map<String, String> summaryStringMetrics = new HashMap<>(plan.getSummaryStringMetrics());
		summaryStringMetrics.merge(TelemetryMetricNames.OPTIMIZER_DECISION_TRACE, decisionTrace,
				(previous, ignored) -> previous + "; " + decisionTrace);
		JoinOrderPlan tracedPlan = new JoinOrderPlan(plan.getOrderedArgs(), plan.getEstimatedFinalRows(),
				plan.getEstimatedTotalWork(), plan.getDiagnostics(), summaryStringMetrics,
				plan.getSummaryDoubleMetrics(), plan.getSteps());
		return PlanningAttempt.planned(tracedPlan, attempt.getPlannerId(), attempt.getAlgorithm(),
				attempt.getPlannerPath(), attempt.getDiagnostics());
	}

	private String boundedGreedySelectedTrace(PlanningAttempt boundedGreedyAttempt) {
		return "bounded-greedy selected (" + attemptEstimateSummary(boundedGreedyAttempt) + ")";
	}

	private String boundedGreedyRejectedTrace(PlanningAttempt boundedGreedyAttempt, PlanningAttempt selectedAttempt) {
		return "bounded-greedy rejected (" + attemptEstimateSummary(boundedGreedyAttempt) + "); "
				+ selectedPlannerLabel(selectedAttempt) + " selected (" + attemptEstimateSummary(selectedAttempt)
				+ ")";
	}

	private String selectedPlannerTrace(PlanningAttempt selectedAttempt) {
		return selectedPlannerLabel(selectedAttempt) + " selected (" + attemptEstimateSummary(selectedAttempt) + ")";
	}

	private String selectedPlannerLabel(PlanningAttempt attempt) {
		if (attempt.getAlgorithm() == Algorithm.DYNAMIC_PROGRAMMING) {
			return "pareto-memo";
		}
		if (attempt.getAlgorithm() == Algorithm.GREEDY) {
			return "pareto-beam";
		}
		return String.valueOf(attempt.getAlgorithm()).toLowerCase();
	}

	private String attemptEstimateSummary(PlanningAttempt attempt) {
		if (attempt.getPlan().isEmpty()) {
			return "path=" + attempt.getPlannerPath() + ", no-plan";
		}
		JoinOrderPlan plan = attempt.getPlan().get();
		return "workRows=" + plan.getEstimatedTotalWork() + ", finalRows=" + plan.getEstimatedFinalRows()
				+ ", path=" + attempt.getPlannerPath();
	}

	private boolean isSmallBoundedGreedyPlan(JoinOrderPlan plan) {
		return isFiniteNonNegative(plan.getEstimatedTotalWork())
				&& plan.getEstimatedTotalWork() <= BOUNDED_GREEDY_MAX_WORK_ROWS
				&& isFiniteNonNegative(plan.getEstimatedFinalRows())
				&& plan.getEstimatedFinalRows() <= BOUNDED_GREEDY_MAX_FINAL_ROWS
				&& boundedUncertaintyRows(plan, BOUNDED_GREEDY_MAX_WORK_ROWS);
	}

	private boolean isFiniteDirectLookupGreedyPlan(JoinOrderPlan plan) {
		if (!isFiniteNonNegative(plan.getEstimatedTotalWork())
				|| plan.getEstimatedTotalWork() > BOUNDED_GREEDY_MAX_DIRECT_LOOKUP_WORK_ROWS
				|| !isFiniteNonNegative(plan.getEstimatedFinalRows())
				|| plan.getEstimatedFinalRows() > BOUNDED_GREEDY_MAX_DIRECT_LOOKUP_ROWS
				|| !boundedUncertaintyRows(plan, BOUNDED_GREEDY_MAX_DIRECT_LOOKUP_WORK_ROWS)
				|| plan.getSteps().size() != plan.getOrderedArgs().size()) {
			return false;
		}
		int directLookupSteps = 0;
		double maxPrefixRows = 0.0d;
		for (int i = 0; i < plan.getOrderedArgs().size(); i++) {
			JoinOrderPlanner.PlanStep step = plan.getSteps().get(i);
			if (!isFiniteNonNegative(step.getStepWorkRows()) || !isFiniteNonNegative(step.getPrefixOutputRows())) {
				return false;
			}
			maxPrefixRows = Math.max(maxPrefixRows, step.getPrefixOutputRows());
			if (LmdbJoinPlanSupport.collectPatternIdentities(plan.getOrderedArgs().get(i)).isEmpty()) {
				continue;
			}
			String accessMode = step.getStringMetrics().get(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE);
			if (!"directLookup".equals(accessMode)) {
				return false;
			}
			directLookupSteps++;
		}
		return directLookupSteps >= BOUNDED_GREEDY_MIN_DIRECT_LOOKUP_STEPS
				&& maxPrefixRows <= BOUNDED_GREEDY_MAX_DIRECT_LOOKUP_ROWS;
	}

	private boolean boundedUncertaintyRows(JoinOrderPlan plan, double maxUncertaintyRows) {
		double uncertaintyRows = plan.getSummaryDoubleMetrics()
				.getOrDefault(TelemetryMetricNames.PLANNED_UNCERTAINTY_ROWS, 0.0d);
		return Double.isFinite(uncertaintyRows)
				&& uncertaintyRows <= maxUncertaintyRows;
	}

	private PlanningAttempt toLmdbPlanningAttempt(PlanningAttempt attempt) {
		if (attempt.getPlan().isEmpty()) {
			return PlanningAttempt.rejected("lmdb-sketch", attempt.getAlgorithm(), attempt.getPlannerPath(),
					attempt.getRejectedFactor(), attempt.getDiagnostics());
		}
		JoinOrderPlan enrichedPlan = enrichPlanWithAccessMetrics(attempt.getPlan().get());
		return PlanningAttempt.planned(enrichedPlan, "lmdb-sketch", attempt.getAlgorithm(), attempt.getPlannerPath(),
				enrichedPlan.getDiagnostics());
	}

	@Override
	public Optional<JoinOrderPlan> estimateJoinOrder(List<TupleExpr> orderedArgs, Set<String> initiallyBoundVars,
			Algorithm algorithm, List<FilterConstraint> deferredFilters) {
		if (!supportsJoinEstimation()) {
			return Optional.empty();
		}
		Optional<JoinOrderPlan> plan = sketchBasedJoinEstimator.estimateJoinOrder(orderedArgs, initiallyBoundVars,
				algorithm, this, deferredFilters);
		if (plan.isEmpty()) {
			return Optional.empty();
		}
		return Optional.of(enrichPlanWithAccessMetrics(plan.get()));
	}

	private JoinOrderPlan enrichPlanWithAccessMetrics(JoinOrderPlan plan) {
		if (plan.getSteps().size() != plan.getOrderedArgs().size()) {
			return plan;
		}

		List<JoinOrderPlanner.PlanStep> enrichedSteps = new ArrayList<>(plan.getSteps().size());
		Map<String, Set<Value>> finiteBindingValues = new HashMap<>();
		for (int i = 0; i < plan.getOrderedArgs().size(); i++) {
			TupleExpr tupleExpr = plan.getOrderedArgs().get(i);
			JoinOrderPlanner.PlanStep step = plan.getSteps().get(i);
			Map<String, String> stringMetrics = new HashMap<>(step.getStringMetrics());
			Map<String, Double> doubleMetrics = new HashMap<>(step.getDoubleMetrics());
			if (!hasAccessMetrics(step)) {
				Optional<FactorCostEstimate> factorCostEstimate = estimateLmdbFactorCost(tupleExpr,
						step.getBoundVarsBefore(), step.getFactorOutputRows(), true,
						finiteBindingValuesForStep(finiteBindingValues, step.getBoundVarsBefore()));
				if (factorCostEstimate.isPresent()) {
					stringMetrics.putAll(factorCostEstimate.get().getStringMetrics());
					doubleMetrics.putAll(factorCostEstimate.get().getDoubleMetrics());
				}
			}
			enrichedSteps.add(new JoinOrderPlanner.PlanStep(step.getBoundVarsBefore(), step.getFactorOutputRows(),
					step.getPrefixOutputRows(), step.getStepWorkRows(), stringMetrics, doubleMetrics,
					step.getAppliedFilterIndexes()));
			addFiniteBindingValues(finiteBindingValues, tupleExpr);
		}

		Map<String, String> summaryStringMetrics = new HashMap<>(plan.getSummaryStringMetrics());
		summaryStringMetrics.put(TelemetryMetricNames.PLANNER_ID, "lmdb-sketch");
		summaryStringMetrics.put(TelemetryMetricNames.OPTIMIZER_PHYSICAL_REFINEMENT,
				"costModel=lmdb, accessPathSelection=per-step");
		return new JoinOrderPlan(plan.getOrderedArgs(), plan.getEstimatedFinalRows(), plan.getEstimatedTotalWork(),
				plan.getDiagnostics(), summaryStringMetrics, plan.getSummaryDoubleMetrics(), enrichedSteps);
	}

	private boolean hasAccessMetrics(JoinOrderPlanner.PlanStep step) {
		return step.getStringMetrics().containsKey(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE)
				|| step.getDoubleMetrics().containsKey(TelemetryMetricNames.PLANNED_ACCESS_ROWS);
	}

	@Override
	public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, Set<String> currentlyBoundVars) {
		if (sketchBasedJoinEstimator == null) {
			return estimatePageWalkingFactorCost(factor);
		}
		return estimateLmdbFactorCost(factor, currentlyBoundVars);
	}

	@Override
	public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, JoinFactorCostModel.CostContext context) {
		if (sketchBasedJoinEstimator == null) {
			return estimatePageWalkingFactorCost(factor);
		}
		if (context == null) {
			return estimateLmdbFactorCost(factor, Set.of());
		}
		Optional<FactorCostEstimate> estimate = estimateLmdbFactorCost(factor, context);
		if (estimate.isEmpty() || !context.isNestedIteratorInvocation() || factor instanceof BindingSetAssignment) {
			return estimate;
		}
		return Optional.of(accountNestedInvocationWork(factor, estimate.get(), context));
	}

	private Optional<FactorCostEstimate> estimatePageWalkingFactorCost(TupleExpr factor) {
		if (factor == null) {
			return Optional.empty();
		}
		double outputRows = estimateFactorOutputRows(factor, Set.of());
		return isFiniteNonNegative(outputRows) ? Optional.of(new FactorCostEstimate(outputRows, outputRows))
				: Optional.empty();
	}

	private Optional<FactorCostEstimate> estimateLmdbFactorCost(TupleExpr factor,
			JoinFactorCostModel.CostContext context) {
		if (context.hasCurrentlyBoundVarMask()) {
			return estimateLmdbFactorCost(factor, context.getVariableNames(), context.getCurrentlyBoundVarMask(),
					Double.NaN, context.shouldCollectMetrics(), context.getFiniteBindingValues());
		}
		return estimateLmdbFactorCost(factor, context.getCurrentlyBoundVars(), Double.NaN,
				context.shouldCollectMetrics(), context.getFiniteBindingValues());
	}

	private FactorCostEstimate accountNestedInvocationWork(TupleExpr factor, FactorCostEstimate estimate,
			JoinFactorCostModel.CostContext context) {
		double outerPrefixRows = context.getOuterPrefixRows();
		if (!isFiniteNonNegative(outerPrefixRows) || outerPrefixRows <= 1.0d) {
			return estimate;
		}
		double workRows = estimate.getWorkRows();
		if (!isFiniteNonNegative(workRows)) {
			return estimate;
		}
		double perInvocationWorkRows = workRows;
		double accessRows = estimate.getAccessRowsBeforeFilter();
		if (isFiniteNonNegative(accessRows)) {
			perInvocationWorkRows = Math.max(perInvocationWorkRows, accessRows);
		}
		double distinctLookupBindings = context.getDistinctLookupBindings();
		double repeatedInvocations = repeatedInvocations(estimate, outerPrefixRows, distinctLookupBindings);
		double multipliedWorkRows = repeatedInvocations * perInvocationWorkRows;
		double nestedWorkRows = isFiniteNonNegative(multipliedWorkRows)
				? Math.max(repeatedInvocations, multipliedWorkRows)
				: Math.max(repeatedInvocations, perInvocationWorkRows);
		double predicateBoundedWorkRows = predicateBoundedRepeatedPrefixWorkRows(factor, estimate, context,
				repeatedInvocations);
		if (isFiniteNonNegative(predicateBoundedWorkRows)) {
			nestedWorkRows = Math.min(nestedWorkRows, predicateBoundedWorkRows);
		}
		if (!isFiniteNonNegative(nestedWorkRows) || nestedWorkRows <= workRows) {
			return estimate;
		}
		Map<String, Double> doubleMetrics = estimate.getDoubleMetrics();
		if (context.shouldCollectMetrics()) {
			doubleMetrics = new HashMap<>(doubleMetrics);
			doubleMetrics.put("plannedRepeatedInvocations", repeatedInvocations);
			doubleMetrics.putIfAbsent(TelemetryMetricNames.PLANNED_ACCESS_WORK_ROWS, perInvocationWorkRows);
			if (isFiniteNonNegative(distinctLookupBindings)) {
				doubleMetrics.put("plannedDistinctLookupBindings", distinctLookupBindings);
			}
		}
		return new FactorCostEstimate(nestedWorkRows, estimate.getOutputRows(), estimate.getStringMetrics(),
				doubleMetrics, estimate.hasPhysicalAccessPath(), estimate.isDirectLookup(),
				estimate.getLookupComponentMask(), estimate.getMissingLookupComponentMask(),
				estimate.getAccessRowsBeforeFilter(), true);
	}

	private double predicateBoundedRepeatedPrefixWorkRows(TupleExpr factor, FactorCostEstimate estimate,
			JoinFactorCostModel.CostContext context, double repeatedInvocations) {
		if (isDirectLookup(estimate) || !isFiniteNonNegative(repeatedInvocations)) {
			return Double.NaN;
		}
		int predicateComponentMask = componentBit(Component.P);
		if ((estimate.getMissingLookupComponentMask() & predicateComponentMask) == 0) {
			return Double.NaN;
		}
		SketchBasedJoinEstimator.AccessShape accessShape = accessShapeForContext(factor, context);
		if (accessShape == null || (accessShape.lookupBoundComponentMask() & predicateComponentMask) == 0) {
			return Double.NaN;
		}
		StatementPattern pattern = accessShape.pattern();
		Var predicateVar = pattern == null ? null : pattern.getPredicateVar();
		if (predicateVar == null || !predicateVar.hasValue()) {
			return Double.NaN;
		}
		double predicateRows = accessShape.estimateAccessRows(predicateComponentMask);
		if (!isFiniteNonNegative(predicateRows)) {
			return Double.NaN;
		}
		double repeatedOutputRows = estimate.getOutputRows() * repeatedInvocations;
		double scanRows = isFiniteNonNegative(repeatedOutputRows)
				? Math.max(predicateRows, repeatedOutputRows)
				: predicateRows;
		return Math.max(repeatedInvocations, scanRows + repeatedInvocations);
	}

	private SketchBasedJoinEstimator.AccessShape accessShapeForContext(TupleExpr factor,
			JoinFactorCostModel.CostContext context) {
		if (sketchBasedJoinEstimator == null) {
			return null;
		}
		if (context.hasCurrentlyBoundVarMask()) {
			return sketchBasedJoinEstimator.accessShapeForJoinOrdering(factor, context.getVariableNames(),
					context.getCurrentlyBoundVarMask());
		}
		return sketchBasedJoinEstimator.accessShapeForJoinOrdering(factor, context.getCurrentlyBoundVars());
	}

	private double repeatedInvocations(FactorCostEstimate estimate, double outerPrefixRows,
			double distinctLookupBindings) {
		if (isDirectLookup(estimate) && isFiniteNonNegative(distinctLookupBindings) && distinctLookupBindings > 0.0d) {
			return Math.min(outerPrefixRows, distinctLookupBindings);
		}
		return outerPrefixRows;
	}

	private boolean isDirectLookup(FactorCostEstimate estimate) {
		return estimate.isDirectLookup()
				|| "directLookup"
						.equals(estimate.getStringMetrics().get(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE));
	}

